// schema.service.ts
import { Injectable, Inject } from '@angular/core';
import { DOCUMENT } from '@angular/common';

@Injectable({ providedIn: 'root' })
export class SchemaService {

	constructor(@Inject(DOCUMENT) private document: Document) { }

	injectServiceSchema(serviceName: string, testimonials: any[]) {

		if (!testimonials || testimonials.length === 0) return;

		// Remove existing schema (SSR hydration fix)
		const existing = this.document.getElementById('service-schema');
		if (existing) existing.remove();

		const reviewCount = testimonials.length;

		const avgRating =
			testimonials.reduce((sum, t) => sum + (t.rating || 5), 0) / reviewCount;

		const schema = {
			"@context": "https://schema.org",
			// "@type": "Service",
			"@type": "LocalBusiness",
			"name": serviceName,
			"aggregateRating": {
				"@type": "AggregateRating",
				"ratingValue": avgRating.toFixed(1),
				"reviewCount": reviewCount,
				"bestRating": "5",
				"worstRating": "1"
				// ,
				// "itemReviewed": {
				// 	"@type": "Service",
				// 	"name": serviceName
				// }
			},
			"review": testimonials.slice(0, 5).map(t => ({
				"@type": "Review",
				"datePublished": t.created_at
					? new Date(t.created_at).toISOString().split('T')[0]
					: new Date().toISOString().split('T')[0],
				// "itemReviewed": {
				// 	"@type": "Service",
				// 	"name": serviceName
				// },
				"author": {
					"@type": "Person",
					"name": t.authorName
				},
				"reviewRating": {
					"@type": "Rating",
					"ratingValue": t.rating || 5,
					"bestRating": "5",
					"worstRating": "1"
				},
				"reviewBody": (t.text || '').replace(/\n/g, ' ').trim()
			}))
		};

		const script = this.document.createElement('script');
		script.id = 'service-schema';
		script.type = 'application/ld+json';
		script.text = JSON.stringify(schema);

		this.document.head.appendChild(script);
	}
}
